	    const groups = candidates.reduce((acc, row) => {
	      const pkg = String(row.workPackage || row.packageName || 'Основная').trim() || 'Основная';
	      if (!acc[pkg]) acc[pkg] = [];
	      acc[pkg].push(row);
	      return acc;
	    }, {});
