                                  const dColor = accepted ? C.success : rejected ? C.danger : C.info;
                                  const dBg = accepted ? C.successLight : rejected ? C.dangerLight : C.infoLight;
                                  const dBorder = accepted ? C.successBorder : rejected ? C.dangerBorder : C.infoBorder;
